using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        /// <summary>
        /// Creates a fresh InMemory SchoolContext with a unique database name.
        /// </summary>
        public static SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        /// <summary>
        /// Creates an InMemory SchoolContext pre-seeded with test data.
        /// </summary>
        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            var context = CreateContext(dbName);
            SeedTestData(context);
            return context;
        }

        /// <summary>
        /// Seeds minimal representative test data into the context.
        /// </summary>
        public static void SeedTestData(SchoolContext context)
        {
            // Add department
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            // Add students
            var students = new[]
            {
                new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { LastName = "Adams", FirstMidName = "Alice", EnrollmentDate = DateTime.Parse("2020-09-01") }
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            // Add instructor with office assignment
            var instructor = new Instructor
            {
                LastName = "Johnson",
                FirstMidName = "Bob",
                HireDate = DateTime.Parse("2000-01-01"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            // Set department admin
            dept.InstructorID = instructor.ID;
            context.SaveChanges();

            // Add courses
            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            // Add enrollment
            context.Enrollments.Add(new Enrollment
            {
                StudentID = students[0].ID,
                CourseID = 1050,
                Grade = Grade.A
            });
            context.SaveChanges();

            // Add course assignment
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = 1050
            });
            context.SaveChanges();
        }

        /// <summary>
        /// Drains the static notification queue to prevent test pollution.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);

            // Assert
            Assert.AreEqual(3, list.PageIndex);
        }

        [TestMethod]
        [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
        [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages (ceiling)")]
        [DataRow(0, 5, 0, DisplayName = "0 items = 0 pages")]
        [DataRow(1, 1, 1, DisplayName = "1 item, page size 1 = 1 page")]
        [DataRow(5, 10, 1, DisplayName = "5 items, page size 10 = 1 page")]
        public void Constructor_SetsTotalPages(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_ContainsAllItems()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 1, 5);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "Page 1 has no previous page")]
        [DataRow(2, true, DisplayName = "Page 2 has previous page")]
        [DataRow(5, true, DisplayName = "Page 5 has previous page")]
        public void HasPreviousPage_ReturnsExpected(int pageIndex, bool expected)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 10);

            // Assert
            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 20, 10, true, DisplayName = "Page 1 of 2 has next page")]
        [DataRow(2, 20, 10, false, DisplayName = "Last page has no next page")]
        [DataRow(1, 5, 10, false, DisplayName = "Single page has no next page")]
        public void HasNextPage_ReturnsExpected(int pageIndex, int totalCount, int pageSize, bool expected)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(20, result[9]);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 3);

            // Assert
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(2, result.TotalPages);
            Assert.AreEqual(3, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(3, result[2]);
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 7).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 3);

            // Assert
            Assert.AreEqual(3, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(7, result[0]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using System;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification_CanBeReceived()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "admin");
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.DELETE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CustomUserName_IsUsed()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("admin", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void ReceiveNotification_MultipleSends_ReturnsFIFOOrder()
        {
            // Arrange
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", EntityOperation.DELETE);

            // Act
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();
            var fourth = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
            Assert.AreEqual("Department", third.EntityType);
            Assert.IsNull(fourth);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
            // No exception thrown = pass
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - no exception
            var service = new NotificationService();
            service.Dispose();
            service.Dispose();
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }
    }
}

