                new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { LastName = "Adams", FirstMidName = "Alice", EnrollmentDate = DateTime.Parse("2020-09-01") }
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            // Add instructor with office assignment
            var instructor = new Instructor
            {
                LastName = "Johnson",
                FirstMidName = "Bob",
                HireDate = DateTime.Parse("2000-01-01"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            // Set department admin
            dept.InstructorID = instructor.ID;
            context.SaveChanges();

            // Add courses
            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            // Add enrollment
            context.Enrollments.Add(new Enrollment
            {
                StudentID = students[0].ID,
                CourseID = 1050,
                Grade = Grade.A
            });
            context.SaveChanges();

            // Add course assignment
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = 1050
            });
            context.SaveChanges();
        }

        /// <summary>
        /// Drains the static notification queue to prevent test pollution.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);

            // Assert
            Assert.AreEqual(3, list.PageIndex);
        }

        [TestMethod]
        [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
        [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages (ceiling)")]
        [DataRow(0, 5, 0, DisplayName = "0 items = 0 pages")]
        [DataRow(1, 1, 1, DisplayName = "1 item, page size 1 = 1 page")]
        [DataRow(5, 10, 1, DisplayName = "5 items, page size 10 = 1 page")]
        public void Constructor_SetsTotalPages(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_ContainsAllItems()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 1, 5);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "Page 1 has no previous page")]
        [DataRow(2, true, DisplayName = "Page 2 has previous page")]
        [DataRow(5, true, DisplayName = "Page 5 has previous page")]
        public void HasPreviousPage_ReturnsExpected(int pageIndex, bool expected)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 10);

            // Assert
            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 20, 10, true, DisplayName = "Page 1 of 2 has next page")]
        [DataRow(2, 20, 10, false, DisplayName = "Last page has no next page")]
        [DataRow(1, 5, 10, false, DisplayName = "Single page has no next page")]
        public void HasNextPage_ReturnsExpected(int pageIndex, int totalCount, int pageSize, bool expected)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(20, result[9]);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 3);

            // Assert
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(2, result.TotalPages);
            Assert.AreEqual(3, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(3, result[2]);
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
