using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using System;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification_CanBeReceived()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "admin");
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.DELETE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CustomUserName_IsUsed()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("admin", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void ReceiveNotification_MultipleSends_ReturnsFIFOOrder()
        {
            // Arrange
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", EntityOperation.DELETE);

            // Act
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();
            var fourth = _sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
            Assert.AreEqual("Department", third.EntityType);
            Assert.IsNull(fourth);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
            // No exception thrown = pass
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - no exception
            var service = new NotificationService();
            service.Dispose();
            service.Dispose();
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
