        [TestMethod]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            // Arrange
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            // Act & Assert
            Assert.AreEqual("Smith, John", student.FullName);
        }

        [TestMethod]
        public void Person_FullName_WorksForInstructor()
        {
            // Arrange
            var instructor = new Instructor { LastName = "Johnson", FirstMidName = "Bob" };

            // Act & Assert
            Assert.AreEqual("Johnson, Bob", instructor.FullName);
        }

        // --- ErrorViewModel ---

        [TestMethod]
        [DataRow("abc-123", true, DisplayName = "Non-empty RequestId shows")]
        [DataRow(null, false, DisplayName = "Null RequestId hidden")]
        [DataRow("", false, DisplayName = "Empty RequestId hidden")]
        public void ErrorViewModel_ShowRequestId_ReturnsExpected(string requestId, bool expected)
        {
            // Arrange
            var model = new ErrorViewModel { RequestId = requestId };

            // Act & Assert
            Assert.AreEqual(expected, model.ShowRequestId);
        }

        // --- Grade Enum ---

        [TestMethod]
        [DataRow(0, "A", DisplayName = "Grade.A = 0")]
        [DataRow(1, "B", DisplayName = "Grade.B = 1")]
        [DataRow(2, "C", DisplayName = "Grade.C = 2")]
        [DataRow(3, "D", DisplayName = "Grade.D = 3")]
        [DataRow(4, "F", DisplayName = "Grade.F = 4")]
        public void Grade_HasExpectedValues(int value, string name)
        {
            var grade = (Grade)value;
            Assert.AreEqual(name, grade.ToString());
        }

        // --- EntityOperation Enum ---

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "CREATE", DisplayName = "CREATE")]
        [DataRow(EntityOperation.UPDATE, "UPDATE", DisplayName = "UPDATE")]
        [DataRow(EntityOperation.DELETE, "DELETE", DisplayName = "DELETE")]
        public void EntityOperation_HasExpectedValues(EntityOperation op, string expected)
        {
            Assert.AreEqual(expected, op.ToString());
        }

        // --- Student ---

        [TestMethod]
        public void Student_InheritsFromPerson_HasEnrollmentDate()
        {
            // Arrange
            var date = new DateTime(2020, 9, 1);
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = date
            };

            // Assert
            Assert.AreEqual(1, student.ID);
            Assert.AreEqual("Test, User", student.FullName);
            Assert.AreEqual(date, student.EnrollmentDate);
            Assert.IsInstanceOfType<Person>(student);
        }

        // --- Instructor ---

        [TestMethod]
        public void Instructor_InheritsFromPerson_HasHireDate()
        {
            // Arrange
            var date = new DateTime(2000, 1, 15);
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = date
            };

            // Assert
            Assert.AreEqual(1, instructor.ID);
            Assert.AreEqual("Prof, Test", instructor.FullName);
            Assert.AreEqual(date, instructor.HireDate);
            Assert.IsInstanceOfType<Person>(instructor);
        }

        // --- Notification ---

        [TestMethod]
        public void Notification_DefaultIsReadIsFalse()
        {
            var notification = new Notification();

            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void Notification_CanSetAllProperties()
        {
            // Arrange
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = true,
                ReadAt = now
            };

            // Assert
            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New student created", notification.Message);
            Assert.AreEqual(now, notification.CreatedAt);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsTrue(notification.IsRead);
            Assert.AreEqual(now, notification.ReadAt);
        }

        // --- InstructorIndexData ---

        [TestMethod]
        public void InstructorIndexData_CanSetCollections()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor> { new Instructor { LastName = "A", FirstMidName = "B" } },
                Courses = new List<Course> { new Course { CourseID = 1, Title = "Test" } },
                Enrollments = new List<Enrollment>()
            };

            Assert.AreEqual(1, data.Instructors.Count());
            Assert.AreEqual(1, data.Courses.Count());
            Assert.AreEqual(0, data.Enrollments.Count());
        }

        // --- AssignedCourseData ---

        [TestMethod]
        public void AssignedCourseData_CanSetProperties()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.AreEqual(1050, data.CourseID);
            Assert.AreEqual("Chemistry", data.Title);
            Assert.IsTrue(data.Assigned);
        }

        // --- Course ---

        [TestMethod]
        public void Course_HasExpectedProperties()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        // --- Department ---

        [TestMethod]
        public void Department_HasExpectedProperties()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("Engineering", dept.Name);
            Assert.AreEqual(350000m, dept.Budget);
            Assert.AreEqual(new DateTime(2007, 9, 1), dept.StartDate);
            Assert.AreEqual(5, dept.InstructorID);
        }

        // --- Enrollment ---

        [TestMethod]
        [DataRow(null, DisplayName = "Null grade")]
        [DataRow(Grade.A, DisplayName = "Grade A")]
        [DataRow(Grade.F, DisplayName = "Grade F")]
        public void Enrollment_SupportsNullableGrade(Grade? grade)
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = grade
            };

            Assert.AreEqual(grade, enrollment.Grade);
        }

        // --- EnrollmentDateGroup ---

        [TestMethod]
        public void EnrollmentDateGroup_CanSetProperties()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2020, 9, 1),
                StudentCount = 15
            };

            Assert.AreEqual(new DateTime(2020, 9, 1), group.EnrollmentDate);
            Assert.AreEqual(15, group.StudentCount);
        }

        // --- OfficeAssignment ---

        [TestMethod]
        public void OfficeAssignment_HasExpectedProperties()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Thompson 304"
            };

            Assert.AreEqual(1, office.InstructorID);
            Assert.AreEqual("Thompson 304", office.Location);
        }

        // --- CourseAssignment ---

        [TestMethod]
        public void CourseAssignment_HasExpectedProperties()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.AreEqual(1, ca.InstructorID);
            Assert.AreEqual(1050, ca.CourseID);
        }
    }
}

