        public void Initialize_SeedsSevenCourses()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_SeedsEnrollments()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(11, context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsThreeOfficeAssignments()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(3, context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsEightCourseAssignments()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_DoesNotReseedWhenStudentsExist()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            DbInitializer.Initialize(context);
            var originalStudentCount = context.Students.Count();
            var originalCourseCount = context.Courses.Count();

            // Act — second initialization should be a no-op
