        public void Initialize_SeedsCoursesWithCorrectTitles()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.IsNotNull(context.Courses.Find(1050)); // Chemistry
            Assert.IsNotNull(context.Courses.Find(4022)); // Microeconomics
            Assert.IsNotNull(context.Courses.Find(1045)); // Calculus
            Assert.AreEqual("Chemistry", context.Courses.Find(1050).Title);
            Assert.AreEqual("Calculus", context.Courses.Find(1045).Title);
        }

        [TestMethod]
        public void Initialize_SeedsDepartmentsLinkedToInstructors()
        {
