using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
        }

        [TestCleanup]
        public void Cleanup()
        {
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            // Use reflection to inspect anonymous type
            var successProp = value.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(value));
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(0, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_WithPendingItems_ReturnsNotifications()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "admin");
            service.SendNotification("Course", "2", "Chem", EntityOperation.UPDATE, "admin");
            service.Dispose();

            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(value));
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(2, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_LimitsToTenNotifications()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }
            service.Dispose();

            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(10, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_ConsumesDequeuedItems()
        {
            // Arrange
            using var context = TestHelpers.CreateContext();
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);
            service.Dispose();

            var controller = new NotificationsController(context);

            // Act — first call should dequeue
            controller.GetNotifications();
            // Second call should find empty queue
            var result = controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(0, (int)countProp.GetValue(value));
        }
    }
}

